#include<bits/stdc++.h>
using namespace std;
int main() {
	string a;
	int ans = 0, maxans = 0, maxi = 0, maxj = 0;;
	cin >> a;
	for (int i = 0; i < a.size(); i++) {
		if ((i + 1) % 5 == 1) {
			if (a[i] == '0' && a[i + 1] == '0' && a[i + 2] == '0' && a[i + 3] == '0') {

				ans++;
				if (maxans < ans) {
					maxans = ans;
					maxi = i + 5 - ans * 5;
					maxj = i + 4;
				}
			} else {
				ans = 0;
			}
		}
	}
	bool flag = 0;
	for (int i = 0; i < a.size(); i++) {
		if (i < maxi-1 || i > maxj) {
			if(i==maxj){
				cout<<"::";
			}
			if ((i + 1) % 5 == 1) {
				flag = 1;
			}
			if (flag == 1 && (i + 1) % 5 == 0) {
				cout << 0;
			}
			if (a[i] != '0' || !flag) {
				flag = 0;
				cout << a[i];
			}
		}

	}
	if(maxj==a.size()){
		cout<<"::";
	}
	return 0;
}
